changeSet.sql:
CREATE UNIQUE INDEX IF NOT EXISTS uq_channel_user_slug 
ON channel (user_id, slug) 
WHERE organization_id IS NULL;

CREATE UNIQUE INDEX IF NOT EXISTS uq_channel_org_slug 
ON channel (organization_id, slug) 
WHERE organization_id IS NOT NULL;

COMMENT ON COLUMN channel.slug IS 'Hierarchical identifier for channel routing (e.g. errors, myapp.errors, myapp.prod.backend.errors)';
COMMENT ON INDEX uq_channel_user_slug IS 'Ensures slug uniqueness per user for personal channels';
COMMENT ON INDEX uq_channel_org_slug IS 'Ensures slug uniqueness per organization for org channels';
